import SwiftUIstruct NEOListView: View {    @StateObject private var viewModel = NEOViewModel()    var body: some View {        NavigationStack {            ZStack {                // Background                Color.black.ignoresSafeArea()                if viewModel.isLoading {                    loadingView                } else if let error = viewModel.errorMessage {                    errorView(message: error)                } else {                    neoList                }            }            .navigationTitle("Near-Earth Objects")            .navigationBarTitleDisplayMode(.large)            .toolbarBackground(Color.black, for: .navigationBar)            .toolbarColorScheme(.dark, for: .navigationBar)            .toolbar {                ToolbarItem(placement: .topBarTrailing) {                    summaryBadge                }            }        }        .task {            await viewModel.loadNEOs()        }    }    private var neoList: some View {        List(viewModel.neos) { neo in            NavigationLink(destination: NEODetailView(neo: neo)) {                NEORowView(neo: neo)            }            .listRowBackground(Color.gray.opacity(0.1))            .listRowSeparatorTint(Color.white.opacity(0.08))        }        .listStyle(.plain)        .scrollContentBackground(.hidden)        .refreshable {            await viewModel.loadNEOs()        }    }    private var loadingView: some View {        VStack(spacing: 16) {            ProgressView()                .progressViewStyle(CircularProgressViewStyle(tint: .orange))                .scaleEffect(1.5)            Text("Scanning for asteroids…")                .foregroundColor(.gray)                .font(.subheadline)        }    }    private func errorView(message: String) -> some View {        VStack(spacing: 20) {            Image(systemName: "exclamationmark.triangle.fill")                .font(.system(size: 48))                .foregroundColor(.orange)            Text("Something went wrong")                .font(.headline)                .foregroundColor(.white)            Text(message)                .font(.caption)                .foregroundColor(.gray)                .multilineTextAlignment(.center)                .padding(.horizontal)            Button("Try Again") {                Task { await viewModel.loadNEOs() }            }            .buttonStyle(.borderedProminent)            .tint(.orange)        }    }    private var summaryBadge: some View {        VStack(alignment: .trailing, spacing: 0) {            Text("\(viewModel.totalCount) objects")                .font(.caption2)                .foregroundColor(.gray)            Text("\(viewModel.hazardousCount) hazardous")                .font(.caption2.bold())                .foregroundColor(.orange)        }    }}struct NEORowView: View {    let neo: NearEarthObject    var body: some View {        HStack(spacing: 14) {            // Hazard indicator dot            Circle()                .fill(neo.isPotentiallyHazardousAsteroid ? Color.red : Color.green)                .frame(width: 10, height: 10)                .shadow(color: neo.isPotentiallyHazardousAsteroid ? .red : .green, radius: 4)            VStack(alignment: .leading, spacing: 4) {                Text(neo.cleanName)                    .font(.system(.body, design: .monospaced).bold())                    .foregroundColor(.white)                    .lineLimit(1)                HStack(spacing: 8) {                    if let approach = neo.firstCloseApproach {                        Label(approach.missDistance.formattedLunar, systemImage: "moon")                            .font(.caption)                            .foregroundColor(.gray)                    }                }            }            Spacer()            VStack(alignment: .trailing, spacing: 4) {                Text(neo.firstCloseApproach?.closeApproachDate ?? "—")                    .font(.caption2)                    .foregroundColor(.orange)                Text(String(format: "%.0f–%.0f m", neo.diameterMetersMin, neo.diameterMetersMax))                    .font(.caption2)                    .foregroundColor(.gray)            }        }        .padding(.vertical, 8)    }}#Preview {    NEOListView()}